INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c04c7ef7-fbd7-42c2-b450-b9af28b54348',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bitcoin — Understanding the UTXO Model and Its Impact on Transaction Verification$escape$,
  $escape$The Unspent Transaction Output (UTXO) model is a fundamental concept in Bitcoin, where each transaction input refers to a previous unspent output. This model allows for efficient transaction verification, as each input can be verified independently. In Bitcoin, the UTXO model is implemented using the Script language, which defines the spending conditions for each output. The Proof-of-Work (PoW) consensus algorithm secures the network by requiring miners to solve a complex mathematical puzzle, ensuring the integrity of the blockchain. The Lightning Network, a second-layer scaling solution, further enhances the efficiency of Bitcoin transactions by enabling off-chain transactions and reducing the load on the main blockchain.$escape$,
  $escape$const bitcoin = require('bitcoinjs-lib');
const tx = new bitcoin.TransactionBuilder();
const utxo = {
  'txId': '...',
  'outputIndex': 0,
  'address': '...',
  'script': '...',
  'satoshis': 10000
};
console.log(utxo);$escape$,
  $escape$javascript$escape$,
